/usr/bin/bash -lc "python - <<'PY'
import json, pathlib, re
terms=['Thai ammunition','ammunition site','ammunition depot','explosions','mass graves','tarawih','mosque','hamstring','Barcelona','Newcastle United','Gorton and Denton','March 2','technical talks','Iranian airspace','multiple explosions']
paths=list(pathlib.Path('articles/2026/02').glob('2[01]/articles.jsonl'))
for term in terms:
    pat=re.compile(re.escape(term), re.I)
    hits=[]
    for p in paths:
        with p.open() as f:
            for line in f:
                if pat.search(line):
                    try: a=json.loads(line)
                    except: continue
                    hits.append((str(p),a.get('date_publish'),a.get('source'),a.get('title'),a.get('url')))
                    if len(hits)>=5: break
        if len(hits)>=5: break
    print('\\nTERM',term,'hits',len(hits))
    for h in hits:
        print(' | '.join(str(x) for x in h))
PY"

